// Collect all generated add-on results and clean up JSON
const results = [];
const nodeNames = [
  'Generate Youth Version',
  'Generate Small Group Guide',
  'Generate Blog Article',
  'Generate Social Posts',
  'Generate Discussion Questions',
  'Generate Printable Handout'
];

for (const nodeName of nodeNames) {
  try {
    const raw = $(nodeName).item.json.text || $(nodeName).item.json.content || '';
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    results.push(parsed);
  } catch(e) {}
}

const validated = $('Validate Input').item.json;

return [{
  json: {
    user_email: validated.user_email,
    project_id: validated.project_id,
    addons_generated: results,
    generated_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
const addons = data.addons_generated;

let sectionsHtml = addons.map(addon => {
  let html = `<div style="margin-bottom:32px; padding:24px; background:#FAFAFA; border-radius:12px; border:1px solid #E0E0E0;">`;
  html += `<h2 style="color:#534AB7; margin:0 0 16px; font-size:18px;">${addon.addon_type || addon.title}</h2>`;

  if (addon.addon_type === 'Social Posts') {
    html += `<h4 style="color:#1a1a1a;">Facebook</h4><p style="color:#444;">${addon.facebook?.post || ''}</p>`;
    html += `<h4 style="color:#1a1a1a;">Instagram</h4><p style="color:#444;">${addon.instagram?.caption || ''}</p>`;
    html += `<h4 style="color:#1a1a1a;">X / Twitter</h4><ul>${(addon.x_twitter||[]).map(t=>`<li style="color:#444;">${t}</li>`).join('')}</ul>`;
    if (addon.quote_graphic) html += `<p><strong>Quote graphic:</strong> ${addon.quote_graphic}</p>`;
  } else if (addon.addon_type === 'Blog Article') {
    html += `<p style="color:#666; font-style:italic;">${addon.meta_description || ''}</p>`;
    html += `<p style="color:#444;">${addon.introduction || ''}</p>`;
    (addon.body_sections || []).forEach(s => {
      html += `<h4 style="color:#1a1a1a;">${s.heading}</h4><p style="color:#444;">${s.content}</p>`;
    });
    html += `<p style="color:#444;">${addon.conclusion || ''}</p>`;
  } else if (addon.discussion_questions || addon.questions) {
    const qs = addon.discussion_questions || addon.questions || [];
    html += `<ol>${qs.map(q => `<li style="color:#444; margin-bottom:8px;">${typeof q === 'object' ? q.question : q}</li>`).join('')}</ol>`;
  } else if (addon.main_points) {
    (addon.main_points || []).forEach((pt, i) => {
      html += `<p><strong>${i+1}. ${pt.point}</strong></p><p style="color:#444;">${pt.explanation}</p>`;
      if (pt.application) html += `<p style="color:#666;"><em>Application: ${pt.application}</em></p>`;
    });
  } else if (addon.fill_in_sections) {
    (addon.fill_in_sections || []).forEach(s => {
      html += `<p><strong>${s.heading}</strong></p>`;
      (s.blanks||[]).forEach(b => html += `<p style="color:#444;">${b}</p>`);
    });
    if (addon.takeaway_blank) html += `<p style="color:#7F77DD; font-weight:600;">${addon.takeaway_blank}</p>`;
  }
  html += `</div>`;
  return html;
}).join('');

const emailHtml = `
<div style="font-family:Georgia,serif; max-width:700px; margin:0 auto; color:#2C2C2A;">
  <div style="background:#7F77DD; padding:24px 32px; border-radius:12px 12px 0 0;">
    <h1 style="color:white; margin:0;">✚ GraceTools</h1>
    <p style="color:rgba(255,255,255,0.8); margin:8px 0 0;">Your add-ons are ready</p>
  </div>
  <div style="background:white; padding:32px; border:1px solid #E0E0E0;">
    <p style="color:#444; margin-bottom:24px;">Here are your requested add-ons for this sermon. Everything below is yours to copy, edit, and use freely.</p>
    ${sectionsHtml}
  </div>
  <div style="background:#F5F3FF; padding:16px 32px; border-radius:0 0 12px 12px; text-align:center;">
    <p style="color:#888; font-size:12px; margin:0;">© GraceTools | support@gracetools.com</p>
  </div>
</div>`;

return [{ json: { ...data, email_html: emailHtml } }];
